package models

import (
	"time"

	"github.com/google/uuid"
	"github.com/lib/pq"
)

// Preset stores training/study presets generated by the analyst agent.
type Preset struct {
	PresetID        uuid.UUID      `gorm:"type:uuid;primaryKey;default:gen_random_uuid()" json:"preset_id"`
	UserID          uuid.UUID      `gorm:"type:uuid;not null;index:idx_presets_user" json:"user_id"`
	TargetMode      string         `gorm:"type:varchar(20);not null" json:"target_mode"`
	Topics          pq.StringArray `gorm:"type:text[]" json:"topics"`
	Materials       pq.StringArray `gorm:"type:text[]" json:"materials"`
	SourceSessionID *uuid.UUID     `gorm:"type:uuid;index:idx_presets_source" json:"source_session_id,omitempty"`
	CreatedAt       time.Time      `json:"created_at"`
	ExpiresAt       *time.Time     `json:"expires_at,omitempty"`
}

func (Preset) TableName() string {
	return "presets"
}
